# Car Wash - deterministic stem mixer. Installs locally. No AI. Nothing uploaded.
$ErrorActionPreference="Stop"
$dest="$env:USERPROFILE\.carwash"
New-Item -ItemType Directory -Force -Path $dest | Out-Null
$b64=""
[IO.File]::WriteAllBytes("$dest\payload.zip",[Convert]::FromBase64String($b64))
Expand-Archive -Force "$dest\payload.zip" $dest
Remove-Item "$dest\payload.zip"
$py=(Get-Command python -ErrorAction SilentlyContinue).Source
if(-not $py){$py=(Get-Command py -ErrorAction SilentlyContinue).Source}
if(-not $py){Write-Error "need python";exit 1}
& $py -c "import numpy,scipy,soundfile,pyloudnorm" 2>$null
if($LASTEXITCODE -ne 0){ & $py -m pip install --quiet numpy scipy soundfile pyloudnorm }
Set-Content "$dest\carwash.bat" "@echo off`r`n`"$py`" `"$dest\carwash.py`" %*"
Write-Host ""
Write-Host "installed. opening Car Wash - type 'yes' then 'mix'."
Write-Host "(everything runs here; your audio never leaves this machine)"
& $py "$dest\carwash.py" go
